package com.ruoyi.modules.invest.benefit.indicator.controller;
import com.ruoyi.common.annotation.Log;import com.ruoyi.common.core.controller.BaseController;import com.ruoyi.common.core.domain.AjaxResult;import com.ruoyi.common.core.page.TableDataInfo;import com.ruoyi.common.enums.BusinessType;import com.ruoyi.modules.invest.benefit.indicator.domain.InvestBenefitIndicator;import com.ruoyi.modules.invest.benefit.indicator.service.IInvestBenefitIndicatorService;import org.apache.shiro.authz.annotation.RequiresPermissions;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.web.bind.annotation.*;@RestController@RequestMapping("/invest/benefit/indicator")public class InvestBenefitIndicatorController extends BaseController{@Autowired private IInvestBenefitIndicatorService service;@RequiresPermissions("invest:benefit:indicator:list")@GetMapping("/list")public TableDataInfo list(InvestBenefitIndicator i){startPage();return getDataTable(service.selectList(i));}@RequiresPermissions("invest:benefit:indicator:list")@GetMapping("/options")public AjaxResult options(){InvestBenefitIndicator i=new InvestBenefitIndicator();i.setStatus("0");return success(service.selectList(i));}@RequiresPermissions("invest:benefit:indicator:list")@GetMapping("/{id}")public AjaxResult get(@PathVariable Long id){return success(service.selectById(id));}@RequiresPermissions("invest:benefit:indicator:add")@Log(title="效益指标",businessType=BusinessType.INSERT)@PostMapping public AjaxResult add(@RequestBody InvestBenefitIndicator i){return toAjax(service.insert(i));}@RequiresPermissions("invest:benefit:indicator:edit")@Log(title="效益指标",businessType=BusinessType.UPDATE)@PutMapping public AjaxResult edit(@RequestBody InvestBenefitIndicator i){return toAjax(service.update(i));}@RequiresPermissions("invest:benefit:indicator:remove")@Log(title="效益指标",businessType=BusinessType.DELETE)@DeleteMapping("/{ids}")public AjaxResult remove(@PathVariable Long[] ids){return toAjax(service.deleteByIds(ids));}}